import React, { useState } from "react";
// FĂRĂ import de CSS sau video aici - se bazează pe părinte (ProfilePage)

export default function UpdateAccount() {
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");


    return (
        <div className="profile-container">
            <div className="profile">
                <h2>Update Account</h2>


                <div className="form-group">
                    <label htmlFor="update-username">New username</label>
                    <input
                        id="update-username"
                        type="text"
                        placeholder="New username"
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                    />
                </div>

                <div className="form-group">
                    <label htmlFor="update-password">New password</label>
                    <input
                        id="update-password"
                        type="password"
                        placeholder="New password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                    />
                </div>

                {/* Am adăugat clasele corecte din ProfilePage.css */}
                <button className="update-button">Actualizează</button>

                {/* Butonul acesta este redundant (există deja în DeleteAccount.tsx)
                dar dacă vrei să îl păstrezi, folosește clasa corectă */}
                <button className="delete-button" style={{marginTop: "10px"}}>
                    Șterge contul
                </button>

            </div>
        </div>
     );
}
